 *   n > 1, divisor >= 2.
 *
 * Effects:
 *   Recursively counts the total number of prime factors of n,
 *   trying divisors starting at divisor.
 */
static unsigned int
count_factors_recursive_helper(unsigned int n, unsigned int divisor)
{
	if (divisor * divisor > n)
		return (1);
	if (n % divisor == 0)
		return (1 + count_factors_recursive_helper(n / divisor, divisor));
	return (count_factors_recursive_helper(n, divisor + 1));
}

