static unsigned int
count_factors(unsigned int n)
{
	unsigned int count = 0;
	unsigned int divisor;

	assert(n > 1);
	for (divisor = 2; divisor * divisor <= n; divisor++) {
		while (n % divisor == 0) {
			count++;
			n /= divisor;
		}
	}
	if (n > 1)
		count++;
	return (count);
}

